import java.util.*;

class Solution {
    public int splitSQLToFiles(int splitLine, List<String> sqlText) {
        // 1. 合法性校验
        if (splitLine < 1 || splitLine > 10000) return 0;
        int n = sqlText.size();
        if (n == 0) return 0;

        // 2. 解析事务标签
        Map<String, Set<Integer>> tagToRows = new HashMap<>();
        for (int idx = 0; idx < n; idx++) {
            String[] statements = sqlText.get(idx).split(";");
            // 去掉末尾空串
            int end = statements.length;
            while (end > 0 && statements[end - 1].isEmpty()) end--;

            for (int s = 0; s < end; s++) {
                String stmt = statements[s].trim();
                if (stmt.isEmpty() || !stmt.startsWith("[")) continue;
                int br = stmt.indexOf(']');
                if (br == -1) continue;
                String tag = stmt.substring(1, br);
                if (tag.startsWith("T")) {
                    tagToRows.computeIfAbsent(tag, k -> new HashSet<>()).add(idx);
                }
            }
        }

        // 3. 并查集
        int[] parent = new int[n];
        for (int i = 0; i < n; i++) parent[i] = i;

        int[] find = new int[1];
        // 递归 find（用循环展开）
        for (Set<Integer> rows : tagToRows.values()) {
            if (rows.size() <= 1) continue;
            Integer[] arr = rows.toArray(new Integer[0]);
            // 找 root
            int root = arr[0];
            while (parent[root] != root) root = parent[root];
            for (int i = 1; i < arr.length; i++) {
                int r = arr[i];
                while (parent[r] != r) r = parent[r];
                if (r != root) parent[r] = root;
            }
        }
        // 路径压缩
        for (int i = 0; i < n; i++) {
            int r = i;
            while (parent[r] != r) r = parent[r];
            parent[i] = r;
        }

        // 4. 分组
        Map<Integer, int[]> groups = new HashMap<>(); // root → [minIdx, count]
        for (int i = 0; i < n; i++) {
            int root = parent[i];
            int[] g = groups.get(root);
            if (g == null) {
                groups.put(root, new int[]{i, 1});
            } else {
                if (i < g[0]) g[0] = i;
                g[1]++;
            }
        }

        List<int[]> glist = new ArrayList<>(groups.values());
        glist.sort((a, b) -> Integer.compare(a[0], b[0]));

        // 5. 贪心分配
        int files = 0, curSize = 0;
        for (int[] g : glist) {
            if (curSize == 0 || curSize + g[1] > splitLine) {
                files++;              // 新建文件（即使超限也独占）
                curSize = g[1];
            } else {
                curSize += g[1];      // 放入当前文件
            }
        }

        return files;
    }
}
