#include <vector>
#include <string>
#include <unordered_map>
#include <unordered_set>
#include <algorithm>
using namespace std;

class Solution {
public:
    int splitSQLToFiles(int splitLine, vector<string>& sqlText) {
        // 1. 合法性校验
        if (splitLine < 1 || splitLine > 10000) return 0;
        int n = (int)sqlText.size();
        if (n == 0) return 0;

        // 2. 解析标签 → 行号集合
        unordered_map<string, unordered_set<int>> tagToRows;
        for (int idx = 0; idx < n; idx++) {
            const string& row = sqlText[idx];
            size_t start = 0;
            while (start <= row.size()) {
                size_t semi = row.find(';', start);
                string stmt = (semi == string::npos)
                    ? row.substr(start) : row.substr(start, semi - start);
                // 跳过空串（末尾无分号时可能为空）
                if (!stmt.empty()) {
                    // 去除前后空格
                    size_t s = stmt.find_first_not_of(' ');
                    if (s != string::npos) {
                        size_t e = stmt.find_last_not_of(' ');
                        stmt = stmt.substr(s, e - s + 1);
                    }
                    if (!stmt.empty() && stmt[0] == '[') {
                        size_t br = stmt.find(']');
                        if (br != string::npos) {
                            string tag = stmt.substr(1, br - 1);
                            if (!tag.empty() && tag[0] == 'T')
                                tagToRows[tag].insert(idx);
                        }
                    }
                }
                if (semi == string::npos) break;
                start = semi + 1;
            }
        }

        // 3. 并查集
        vector<int> parent(n);
        for (int i = 0; i < n; i++) parent[i] = i;
        for (auto& kv : tagToRows) {
            const auto& rows = kv.second;
            if (rows.size() <= 1) continue;
            int first = *rows.begin();
            for (auto it = next(rows.begin()); it != rows.end(); ++it) {
                // 合并到 first
                int px = first, py = *it;
                while (parent[px] != px) px = parent[px];
                while (parent[py] != py) py = parent[py];
                if (px != py) parent[py] = px;
            }
        }
        // 路径压缩
        for (int i = 0; i < n; i++) {
            int r = i;
            while (parent[r] != r) r = parent[r];
            parent[i] = r;
        }

        // 4. 分组 → (首次出现行号, 行数)
        unordered_map<int, pair<int, int>> groups;
        for (int i = 0; i < n; i++) {
            int root = parent[i];
            auto it = groups.find(root);
            if (it == groups.end())
                groups[root] = {i, 1};
            else {
                it->second.first = min(it->second.first, i);
                it->second.second++;
            }
        }
        vector<pair<int, int>> glist;
        for (auto& kv : groups) glist.push_back(kv.second);
        sort(glist.begin(), glist.end());

        // 5. 贪心分配
        int files = 0, curSize = 0;
        for (auto& g : glist) {
            if (curSize == 0 || curSize + g.second > splitLine) {
                files++;              // 新建文件（即使超限也独占）
                curSize = g.second;
            } else {
                curSize += g.second;  // 放入当前文件
            }
        }
        return files;
    }
};
