var splitSQLToFiles = function(splitLine, sqlText) {
    // 1. 合法性校验
    if (splitLine < 1 || splitLine > 10000) return 0;
    const n = sqlText.length;
    if (n === 0) return 0;

    // 2. 解析标签 → 行号集合
    const tagToRows = {};
    for (let idx = 0; idx < n; idx++) {
        const statements = sqlText[idx].split(';');
        const end = statements.length > 0 && statements[statements.length - 1] === ''
            ? statements.length - 1 : statements.length;
        for (let s = 0; s < end; s++) {
            const stmt = statements[s].trim();
            if (!stmt || !stmt.startsWith('[')) continue;
            const br = stmt.indexOf(']');
            if (br === -1) continue;
            const tag = stmt.substring(1, br);
            if (tag.startsWith('T')) {
                if (!tagToRows[tag]) tagToRows[tag] = new Set();
                tagToRows[tag].add(idx);
            }
        }
    }

    // 3. 并查集
    const parent = Array.from({ length: n }, (_, i) => i);
    const find = (x) => {
        while (parent[x] !== x) {
            parent[x] = parent[parent[x]];
            x = parent[x];
        }
        return x;
    };
    const union = (x, y) => {
        const px = find(x), py = find(y);
        if (px !== py) parent[px] = py;
    };

    for (const rows of Object.values(tagToRows)) {
        const arr = [...rows];
        for (let i = 1; i < arr.length; i++)
            union(arr[0], arr[i]);
    }

    // 4. 分组
    const groups = {};
    for (let i = 0; i < n; i++) {
        const root = find(i);
        if (!groups[root]) groups[root] = [i, 0];
        if (i < groups[root][0]) groups[root][0] = i;
        groups[root][1]++;
    }
    const glist = Object.values(groups).sort((a, b) => a[0] - b[0]);

    // 5. 贪心分配
    let files = 0, curSize = 0;
    for (const [, gsize] of glist) {
        if (curSize === 0 || curSize + gsize > splitLine) {
            files++;              // 新建文件（即使超限也独占）
            curSize = gsize;
        } else {
            curSize += gsize;     // 放入当前文件
        }
    }

    return files;
};
